    val context = LocalContext.current
    val startMeasure = {
        val toast = if (metric.type == RingMetricType.TEMPERATURE) {
            "已开启体温定时采集，稍后会读取历史体温"
        } else {
            "开始测量${metric.title}，请保持戒指佩戴稳定"
