import android.content.Context
import android.util.Log
import androidx.work.BackoffPolicy
import androidx.work.Constraints
import androidx.work.CoroutineWorker
import androidx.work.ExistingPeriodicWorkPolicy
import androidx.work.NetworkType
import androidx.work.PeriodicWorkRequestBuilder
import androidx.work.WorkManager
import androidx.work.WorkerParameters
import com.rehealth.genie.ReHealthApplication
import com.rehealth.genie.network.TelemetryUploadOutcome
import com.rehealth.genie.ring.RingBackgroundCollectionSettings
import java.util.concurrent.TimeUnit

class MeasurementSyncWorker(
    appContext: Context,
    workerParams: WorkerParameters,
) : CoroutineWorker(appContext, workerParams) {
    override suspend fun doWork(): Result {
        if (!RingBackgroundCollectionSettings.isActive(applicationContext)) {
            return Result.success()
        }
        val application = applicationContext as? ReHealthApplication
            ?: return Result.failure()
        val repository = application.measurementSyncRepository
        repository.resetInterruptedUploads()
        repository.purgeOldDone()

        repeat(MAX_BATCHES_PER_RUN) {
            repository.enqueueNextBatch()
            val queued = repository.claimNext() ?: return Result.success()
            val batch = repository.decode(queued)
            if (batch == null) {
                repository.markFailed(queued, "MALFORMED_QUEUE_PAYLOAD")
                return Result.failure()
            }
            when (val decision = MeasurementSyncRetryPolicy.decide(
                application.reHealthMobileApi.uploadMeasurements(batch),
                queued.attemptCount,
            )) {
                MeasurementSyncDecision.Done -> repository.markDone(queued)
                MeasurementSyncDecision.AuthPaused -> {
                    repository.markFailed(queued, "AUTH_REJECTED")
                    repository.pauseForAuthentication()
                    Log.w(TAG, "telemetry sync paused: authentication rejected")
                    return Result.success()
                }
                is MeasurementSyncDecision.PermanentFailure -> {
                    repository.markFailed(queued, decision.errorCode)
                    Log.w(TAG, "telemetry batch permanently failed: ${decision.errorCode}")
                    return Result.failure()
                }
                is MeasurementSyncDecision.Retry -> {
                    repository.markRetryable(queued, decision.errorCode)
                    return Result.retry()
                }
            }
        }
        return Result.success()
    }

    companion object {
        private const val TAG = "MeasurementSyncWorker"
        private const val UNIQUE_WORK_NAME = "measurement_telemetry_sync"
        private const val MAX_BATCHES_PER_RUN = 10

        fun schedule(context: Context) {
            val request = PeriodicWorkRequestBuilder<MeasurementSyncWorker>(15, TimeUnit.MINUTES)
                .setConstraints(
                    Constraints.Builder()
                        .setRequiredNetworkType(NetworkType.CONNECTED)
                        .setRequiresBatteryNotLow(true)
                        .build(),
                )
                .setBackoffCriteria(BackoffPolicy.EXPONENTIAL, 30, TimeUnit.SECONDS)
                .build()
            WorkManager.getInstance(context.applicationContext).enqueueUniquePeriodicWork(
                UNIQUE_WORK_NAME,
                ExistingPeriodicWorkPolicy.KEEP,
                request,
            )
        }
    }
}

internal sealed class MeasurementSyncDecision {
    data object Done : MeasurementSyncDecision()
    data object AuthPaused : MeasurementSyncDecision()
    data class Retry(val errorCode: String) : MeasurementSyncDecision()
    data class PermanentFailure(val errorCode: String) : MeasurementSyncDecision()
}

internal object MeasurementSyncRetryPolicy {
    private const val MAX_ATTEMPTS = 5

    fun decide(outcome: TelemetryUploadOutcome, attemptCount: Int): MeasurementSyncDecision =
        when (outcome) {
            is TelemetryUploadOutcome.Accepted -> MeasurementSyncDecision.Done
            is TelemetryUploadOutcome.Rejected ->
                MeasurementSyncDecision.PermanentFailure("BACKEND_${outcome.status}")
            is TelemetryUploadOutcome.HttpFailure -> when {
                outcome.statusCode == 401 || outcome.statusCode == 403 -> MeasurementSyncDecision.AuthPaused
                outcome.statusCode in 400..499 ->
                    MeasurementSyncDecision.PermanentFailure("HTTP_${outcome.statusCode}")
                attemptCount >= MAX_ATTEMPTS ->
                    MeasurementSyncDecision.PermanentFailure("HTTP_RETRY_EXHAUSTED")
                else -> MeasurementSyncDecision.Retry("HTTP_${outcome.statusCode}")
            }
            is TelemetryUploadOutcome.TransportFailure -> retryOrExhausted(
                attemptCount,
                "TRANSPORT_${outcome.errorType.uppercase()}",
            )
            is TelemetryUploadOutcome.InvalidResponse -> retryOrExhausted(
                attemptCount,
                "INVALID_${outcome.reason}",
            )
        }

    private fun retryOrExhausted(attemptCount: Int, errorCode: String): MeasurementSyncDecision =
        if (attemptCount >= MAX_ATTEMPTS) {
            MeasurementSyncDecision.PermanentFailure("RETRY_EXHAUSTED")
        } else {
            MeasurementSyncDecision.Retry(errorCode)
        }
}
